// ============================================
// EXTRACCIÓN DE DATOS DEL CORREO BANCARIO
// Soporta formatos de Itaú, Continental, BCP, Visión, GNB, etc.
// ============================================

const items = [];

for (const item of $input.all()) {
  const emailText = (item.json.textPlain || item.json.text || item.json.html || '').replace(/<[^>]*>/g, ' ');
  const emailSubject = item.json.subject || '';
  const emailFrom = item.json.from || '';
  const emailDate = item.json.date || new Date().toISOString();
  const emailId = item.json.uid || item.json.messageId || '';
  const accountEmail = item.json.to || '';

  const fullText = emailSubject + ' ' + emailText;

  // ── Monto en Guaraníes ──────────────────────────
  // Formatos: Gs. 150.000, Gs 150000, PYG 150,000, G. 150.000
  let amount = null;
  const amountPatterns = [
    /(?:Gs\.?|PYG|G\.)\s*([\d.,]+)/i,
    /(?:monto|importe|transferencia|acreditación|crédito)(?:[^\d]*)?([\d.,]+)\s*(?:Gs|PYG)?/i,
    /([\d]{3,}(?:[.,][\d]{3})*)/,  // Fallback: any number with thousands separator
  ];

  for (const pattern of amountPatterns) {
    const match = fullText.match(pattern);
    if (match) {
      // Clean up number: remove dots as thousands separators, keep decimal comma
      let cleaned = match[1].replace(/\./g, '').replace(',', '.');
      const parsed = parseFloat(cleaned);
      if (!isNaN(parsed) && parsed > 1000) { // Minimum 1000 Gs to avoid false positives
        amount = Math.round(parsed); // Round to integer (Guaraní has no decimals)
        break;
      }
    }
  }

  // ── Nombre del Pagador ──────────────────────────
  let payerName = null;
  const payerPatterns = [
    /(?:ordenante|remitente|de|from|pagador|cliente)(?:[:\s]+)([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑa-záéíóúñ\s]{3,50})/i,
    /(?:nombre)(?:[:\s]+)([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑa-záéíóúñ\s]{3,50})/i,
  ];
  for (const pattern of payerPatterns) {
    const match = fullText.match(pattern);
    if (match) {
      payerName = match[1].trim().substring(0, 60);
      break;
    }
  }

  // ── Referencia/Comprobante ───────────────────────
  let reference = null;
  const refPatterns = [
    /(?:referencia|comprobante|nro\.?|número|operación|transacción|ref)(?:[:\s#]+)([A-Z0-9\-]{4,30})/i,
    /(?:ID|N°)(?:[:\s]+)([A-Z0-9\-]{4,30})/i,
  ];
  for (const pattern of refPatterns) {
    const match = fullText.match(pattern);
    if (match) {
      reference = match[1].trim();
      break;
    }
  }

  // ── Banco emisor ────────────────────────────────
  let bank = 'Desconocido';
  if (emailFrom.includes('itau')) bank = 'Itaú';
  else if (emailFrom.includes('continental')) bank = 'Continental';
  else if (emailFrom.includes('bcp') || emailFrom.includes('bancopop')) bank = 'BCP/Bancop';
  else if (emailFrom.includes('vision')) bank = 'Visión';
  else if (emailFrom.includes('gnb') || emailFrom.includes('sudameris')) bank = 'GNB Sudameris';

  // ── Validación mínima ───────────────────────────
  if (!amount) {
    console.log(`[ClickPar] Email sin monto detectado (from: ${emailFrom}, subj: ${emailSubject})`);
    // Skip this email — not parseable
    continue;
  }

  items.push({
    json: {
      email_id: emailId,
      account_email: accountEmail,
      from: emailFrom,
      subject: emailSubject,
      date: emailDate,
      amount,
      payer_name: payerName,
      reference,
      bank,
      raw_text: emailText.substring(0, 500), // first 500 chars for debug
    }
  });
}

return items;

// Attach the Supabase search results to the email extraction data
// The previous node (HTTP Request) returns an array of matching transactions

const emailData = $('🔍 Extraer datos (regex)').first().json;
const matches = $input.all().map(i => i.json);

return [{
  json: {
    ...emailData,
    matches,
    match_count: matches.length,
  }
}];

// Prepare data for auto-verification
const data = $input.first().json;
const match = data.matches[0];
const excedente = data.amount - match.amount;

return [{
  json: {
    ...data,
    transaction_id: match.id,
    subscription_id: match.subscription_id,
    customer: match.profiles,
    matched_amount: match.amount,
    excedente: excedente > 500 ? excedente : 0,
    notes: `Auto-verificado por n8n. Banco: ${data.bank}. Ref: ${data.reference || 'N/D'}. Pagador: ${data.payer_name || 'N/D'}.`,
  }
}];

// Notify owner if excedente was detected
const data = $('⚙️ Preparar auto-verify').first().json;
const result = $input.first().json;

if (data.excedente > 500) {
  return [{
    json: {
      send: true,
      phone: $env.OWNER_PHONE,
      message: [
        `⚠️ *Pago verificado con excedente*`,
        ``,
        `👤 Cliente: ${data.customer?.full_name || 'Desconocido'}`,
        `💰 Esperado: Gs. ${Number(data.matched_amount).toLocaleString('es-PY')}`,
        `💵 Recibido: Gs. ${Number(data.amount).toLocaleString('es-PY')}`,
        `➕ Excedente: *Gs. ${Number(data.excedente).toLocaleString('es-PY')}*`,
        `🏦 Banco: ${data.bank}`,
        `📋 Ref: ${data.reference || 'N/D'}`,
        ``,
        `_La suscripción fue renovada automáticamente._`,
      ].join('\n'),
    }
  }];
}

return [{ json: { send: false } }];

// Build escalation message for owner — multiple matches
const data = $input.first().json;

const matchesList = data.matches.map((m, i) => 
  `${i+1}. ${m.profiles?.full_name || 'Sin nombre'} — Gs. ${Number(m.amount).toLocaleString('es-PY')} (ID: ${m.id.substring(0,8)}...)`
).join('\n');

return [{
  json: {
    phone: $env.OWNER_PHONE,
    message: [
      `⚠️ *Pago bancario - Revisión manual requerida*`,
      ``,
      `Recibí una transferencia de *Gs. ${Number(data.amount).toLocaleString('es-PY')}* pero hay *${data.match_count} clientes* con ese monto pendiente.`,
      ``,
      `🏦 Banco: ${data.bank}`,
      `👤 Pagador: ${data.payer_name || 'No detectado'}`,
      `📋 Ref: ${data.reference || 'No detectada'}`,
      ``,
      `🔎 *Coincidencias encontradas:*`,
      matchesList,
      ``,
      `Para verificar manualmente, respondé con el ID de la transacción o usá el panel de admin.`,
    ].join('\n'),
  }
}];

// Build alert message for owner — no match found
const data = $input.first().json;

return [{
  json: {
    phone: $env.OWNER_PHONE,
    message: [
      `❓ *Transferencia bancaria sin coincidencia*`,
      ``,
      `Recibí un pago que no pudo asignarse automáticamente:`,
      ``,
      `💰 Monto: *Gs. ${Number(data.amount).toLocaleString('es-PY')}*`,
      `🏦 Banco: ${data.bank}`,
      `👤 Pagador: ${data.payer_name || 'No detectado'}`,
      `📋 Ref: ${data.reference || 'No detectada'}`,
      `📅 Fecha: ${data.date}`,
      ``,
      `⚠️ No hay ninguna suscripción pendiente por ese monto (±500 Gs).`,
      `Revisá si es un pago adelantado o un cliente nuevo.`,
    ].join('\n'),
  }
}];

// Mark emails as read using IMAP mark-seen
// This prevents reprocessing the same emails
// NOTE: You need to implement mark-seen via IMAP after reading.
// n8n's IMAP node automatically marks as read when 'markSeen' is enabled on the read operation.
// If not auto-marked, you can use the HTTP Request node to call Gmail API or just log here.
console.log('[ClickPar] Email processed — should be marked as read:', $json.email_id || 'unknown');
return $input.all();
